// 1. Get all items that made it to this node
const allItems = $input.all();

// 2. Use .first() to reliably retrieve the single contact ID
const contactId = $('Edit Fields').first().json.contact_id;

// 3. Initialize the result object with the URLs
const result = {
  contactId: contactId,
  facebook_url: "",
  instagram_url: "",
  linkedin_url: "",
  twitter_url: "",
  google_url: ""
};

// 4. Loop through all items and extract URLs by platform
for (const item of allItems) {
  const url = item.json.permalink || "";

  if (url.includes("facebook.com")) {
    result.facebook_url = url;
  } else if (url.includes("instagram.com")) {
    result.instagram_url = url;
  } else if (url.includes("linkedin.com")) {
    result.linkedin_url = url;
  } else if (url.includes("twitter.com")) {
    result.twitter_url = url; 
  } else if (url.includes("google.com")) {
    result.google_url = url;
  }
}

// 5. Return the result as a single item
return result;

// Get the text from the input
const text = $input.item.json.text || "";

// Define markers
const blogMarker = "**BLOG POST:**";
const xMarker = "**X tweet:**";

// Initialize result object
const result = {
  blog_post: "",
  x_tweet: "",
  error: null
};

try {
  // Check if both markers exist
  if (!text.includes(blogMarker) || !text.includes(xMarker)) {
    result.error = "Missing required markers in text";
    return result;
  }

  // Extract blog post
  const blogStart = text.indexOf(blogMarker) + blogMarker.length;
  const blogEnd = text.indexOf(xMarker);
  result.blog_post = text.substring(blogStart, blogEnd).trim();

  // Extract X tweet
  const xtweetStart = text.indexOf(xMarker) + xMarker.length;
  result.x_tweet = text.substring(xtweetStart).trim();

} catch (error) {
  result.error = error.message;
}

return result;
